//# Pipeline Fork (Blocking)

// Takes in a ready/valid handshake with the associated data, and replicates
// that transaction to multiple outputs. The input can proceed to the next
// transaction once **all** outputs can finish their transactions
// **simultaneously**. This constraint prevents any branch from running ahead
// of the others.

// **NOTE**: If the downstream logic connected to the output interfaces can
// lower their `ready` signal after raising it, before the corresponding
// `valid` is raised to complete the handshake, you could end up with
// deadlocks of unknown duration until all `ready` signals happen to be
// asserted together. To avoid this situation, use an [Eager Pipeline
// Fork](./Pipeline_Fork_Eager.html), but then you cannot guarantee lockstep
// operation of the various downstream logic branches.

// The input is buffered to minimise any long combinational path or loops
// which might happen when using the [Lazy Pipeline
// Fork](./Pipeline_Fork_Lazy.html).

`default_nettype none

module Pipeline_Fork_Blocking
#(
    parameter WORD_WIDTH    = 0,
    parameter OUTPUT_COUNT  = 0,

    // Do not set at instantiation, except in IPI
    parameter TOTAL_WIDTH   = WORD_WIDTH * OUTPUT_COUNT
)
(
    input  wire                     clock,
    input  wire                     clear,

    input  wire                     input_valid,
    output wire                     input_ready,
    input  wire [WORD_WIDTH-1:0]    input_data,

    output wire [OUTPUT_COUNT-1:0]  output_valid,
    input  wire [OUTPUT_COUNT-1:0]  output_ready,
    output wire [TOTAL_WIDTH-1:0]   output_data
);

    wire                    input_valid_buffered;
    wire                    input_ready_buffered;
    wire [WORD_WIDTH-1:0]   input_data_buffered;

    Pipeline_Skid_Buffer
    #(
        .WORD_WIDTH      (WORD_WIDTH),
        .CIRCULAR_BUFFER (0)            // Not meaningful here
    )
    input_buffer
    (
        .clock           (clock),
        .clear           (clear),

        .input_valid     (input_valid),
        .input_ready     (input_ready),
        .input_data      (input_data),

        .output_valid    (input_valid_buffered),
        .output_ready    (input_ready_buffered),
        .output_data     (input_data_buffered)
    );

    Pipeline_Fork_Lazy
    #(
        .WORD_WIDTH     (WORD_WIDTH),
        .OUTPUT_COUNT   (OUTPUT_COUNT)
    )
    output_fork
    (
        .input_valid    (input_valid_buffered),
        .input_ready    (input_ready_buffered),
        .input_data     (input_data_buffered),

        .output_valid   (output_valid),
        .output_ready   (output_ready),
        .output_data    (output_data)
    );

endmodule

//# Pipeline Fork (Lazy)

// Takes in a ready/valid handshake along with the associated data, and
// replicates that transaction to multiple outputs. The input can proceed to
// the next transaction once **all** outputs have finished their transactions.
// *All input and output transactions complete simultaneously.*

// There is no buffering, so be careful of combinational paths. If you cannot
// avoid a long combination path (or worse, a loop), then you must use the
// [Eager Pipeline Fork](./Pipeline_Fork_Eager.html).

`default_nettype none

module Pipeline_Fork_Lazy
#(
    parameter WORD_WIDTH    = 0,
    parameter OUTPUT_COUNT  = 0,

    // Do not set at instantiation, except in IPI
    parameter TOTAL_WIDTH   = WORD_WIDTH * OUTPUT_COUNT
)
(
    input  wire                     input_valid,
    output reg                      input_ready,
    input  wire [WORD_WIDTH-1:0]    input_data,

    output reg  [OUTPUT_COUNT-1:0]  output_valid,
    input  wire [OUTPUT_COUNT-1:0]  output_ready,
    output reg  [TOTAL_WIDTH-1:0]   output_data
);

    localparam TOTAL_ZERO   = {TOTAL_WIDTH{1'b0}};
    localparam OUTPUT_ONES  = {OUTPUT_COUNT{1'b1}};
    localparam OUTPUT_ZERO  = {OUTPUT_COUNT{1'b0}};

    initial begin
        input_ready     = 1'b0;
        output_valid    = OUTPUT_ZERO;
        output_data     = TOTAL_ZERO;
    end

// If all outputs are ready, then signal ready to the input and pass the valid
// signal through to all outputs, so all transaction complete together.

    reg output_valid_gated  = 1'b0;

    always @(*) begin
        input_ready         = (output_ready == OUTPUT_ONES);
        output_valid        = {OUTPUT_COUNT{output_valid_gated}};
        output_data         = {OUTPUT_COUNT{input_data}};
    end

    always @(*) begin
        output_valid_gated  = (input_valid == 1'b1) && (input_ready == 1'b1);
    end

endmodule

//# Pipeline Join

// Takes in multiple input ready/valid handshakes with associated data, and
// once all input handshakes can complete, joins them together into a single
// output ready/valid handshake with all data concatenated. This function
// synchronizes multiple pipelines into a single wider one.

//## Avoiding combinational loops

// As a design convention, we must avoid a combinational path between the
// valid and ready signals in a given pipeline interface, because if the other
// end of the pipeline connection also has a ready/valid combinational path,
// connecting these two interfaces will form a combinational loop, which
// cannot be analyzed for timing, or simulated reliably.

// Thus, the input interfaces here are buffered to break the combinational
// path, even if the buffering is redundant. It's not worth the risk of a bad
// simulation or synthesis otherwise.

`default_nettype none

module Pipeline_Join
#(
    parameter WORD_WIDTH     = 0,
    parameter INPUT_COUNT    = 0,

    // Do not set at instantiation, except in IPI
    parameter TOTAL_WIDTH   = WORD_WIDTH * INPUT_COUNT
)
(
    input  wire                     clock,
    input  wire                     clear,

    input  wire [INPUT_COUNT-1:0]   input_valid,
    output wire [INPUT_COUNT-1:0]   input_ready,
    input  wire [TOTAL_WIDTH-1:0]   input_data,

    output reg                      output_valid,
    input  wire                     output_ready,
    output reg  [TOTAL_WIDTH-1:0]   output_data
);

    localparam INPUT_ZERO = {INPUT_COUNT{1'b0}};
    localparam INPUT_ONES = {INPUT_COUNT{1'b1}};
    localparam TOTAL_ZERO = {TOTAL_WIDTH{1'b0}};

    initial begin
        output_valid = 1'b0;
        output_data  = TOTAL_ZERO;
    end

// First, we must buffer the input interfaces to break the combinational paths
// from valid to ready.

    wire [INPUT_COUNT-1:0]   input_valid_buffered;
    reg  [INPUT_COUNT-1:0]   input_ready_buffered = INPUT_ZERO;
    wire [TOTAL_WIDTH-1:0]   input_data_buffered;

    generate
        genvar j;
        for(j=0; j < INPUT_COUNT; j=j+1) begin: per_input
            Pipeline_Skid_Buffer
            #(
                .WORD_WIDTH         (WORD_WIDTH),
                .CIRCULAR_BUFFER    (0)             // Not meaningful here
            )
            input_buffer
            (
                .clock          (clock),
                .clear          (clear),

                .input_valid    (input_valid[j]),
                .input_ready    (input_ready[j]),
                .input_data     (input_data [WORD_WIDTH*j +: WORD_WIDTH]),

                .output_valid   (input_valid_buffered[j]),
                .output_ready   (input_ready_buffered[j]),
                .output_data    (input_data_buffered [WORD_WIDTH*j +: WORD_WIDTH])
            );
        end
    endgenerate

// Once all inputs are valid, declare the output valid and make all the input
// ready equal to the output ready.  Pass the input data to the output data.

    always @(*) begin
        output_valid            = (input_valid_buffered == INPUT_ONES);
        output_data             = input_data_buffered;
    end

    always @(*) begin
        input_ready_buffered    = (output_valid == 1'b1) ? {INPUT_COUNT{output_ready}} : INPUT_ZERO;
    end

endmodule

//# Pipeline Branch (One-Hot)

// Takes an input ready/valid handshake, with associated data, and connects it
// to one of several output ready/valid handshake selected by a one-hot bit
// vector. (Use [Binary to One-Hot](./Binary_to_One_Hot.html) if necessary.)

//## Demultiplexing

// Normally, the `selector` remains stable while transfers are in progress
// (input ready and valid both high), but if you are careful you can change
// the selector each cycle to demultiplex the input data to multiple
// output data.

//## Multiple selected outputs

// Normally, only one bit of the one-hot `selector` must be set at any time.
// If no bit is set, then the input and the outputs are all disconnected and
// no handshake can complete.  If more than one bit is set, then the multiple
// selected outputs each get a copy of the valid signal and the associated
// data (the others get zero), and the input ready receives a Boolean
// OR-reduction of all the selected output ready signals, which sends the data
// to the first selected output which is ready, and any other outputs ready in
// the same cycle. This behaviour is like a non-synchronizing [Eager Pipeline
// Fork](./Pipeline_Fork_Eager.html).

// The IMPLEMENTATION parameter defaults to "AND", and controls the
// implementation of the Annullers inside the mux/demux. It is unlikely you
// will need to change it.

`default_nettype none

module Pipeline_Branch_One_Hot
#(
    parameter WORD_WIDTH        = 0,
    parameter OUTPUT_COUNT      = 0,
    parameter IMPLEMENTATION    = "AND",

    // Do not set at instantiation, except in IPI
    parameter TOTAL_WIDTH = WORD_WIDTH * OUTPUT_COUNT
)
(
    input  wire [OUTPUT_COUNT-1:0]  selector,

    input  wire                     input_valid,
    output wire                     input_ready,
    input  wire [WORD_WIDTH-1:0]    input_data,

    output wire [OUTPUT_COUNT-1:0]  output_valid,
    input  wire [OUTPUT_COUNT-1:0]  output_ready,
    output wire [TOTAL_WIDTH-1:0]   output_data
);

// Steer the selected output ready to the input ready.

    Multiplexer_One_Hot
    #(
        .WORD_WIDTH     (1),
        .WORD_COUNT     (OUTPUT_COUNT),
        .OPERATION      ("OR"),         // Other operations aren't meaningful here.
        .IMPLEMENTATION (IMPLEMENTATION)
    )
    ready_mux
    (
        .selectors      (selector),
        .words_in       (output_ready),
        .word_out       (input_ready)
    );

// Steer the input valid to the selected output valid.

    Demultiplexer_One_Hot
    #(
        .BROADCAST      (0),
        .WORD_WIDTH     (1),
        .OUTPUT_COUNT   (OUTPUT_COUNT),
        .IMPLEMENTATION (IMPLEMENTATION)
    )
    valid_demux
    (
        .selectors      (selector),
        .word_in        (input_valid),
        .words_out      (output_valid),
        // verilator lint_off PINCONNECTEMPTY
        .valids_out     ()
        // verilator lint_on  PINCONNECTEMPTY
    );

// Steer the input data to the selected output data.
// Other outputs get all-zero data.

    Demultiplexer_One_Hot
    #(
        .BROADCAST      (0),
        .WORD_WIDTH     (WORD_WIDTH),
        .OUTPUT_COUNT   (OUTPUT_COUNT),
        .IMPLEMENTATION (IMPLEMENTATION)
    )
    data_demux
    (
        .selectors      (selector),
        .word_in        (input_data),
        .words_out      (output_data),
        // verilator lint_off PINCONNECTEMPTY
        .valids_out     ()
        // verilator lint_on  PINCONNECTEMPTY
    );

endmodule

//# Pipeline Fork (Eager)

// Takes in a ready/valid handshake with the associated data, and replicates
// that transaction to multiple outputs. The input can proceed to the next
// transaction once **all** outputs have finished their transactions.  *Each
// output transaction can complete independently.*

// The outputs are buffered, so each output transaction can complete
// independently, in any order. This also breaks any long combinational path
// or loops which might happen when using the [Lazy Pipeline
// Fork](./Pipeline_Fork_Lazy.html).

`default_nettype none

module Pipeline_Fork_Eager
#(
    parameter WORD_WIDTH    = 0,
    parameter OUTPUT_COUNT  = 0,

    // Do not set at instantiation, except in IPI
    parameter TOTAL_WIDTH   = WORD_WIDTH * OUTPUT_COUNT
)
(
    input  wire                     clock,
    input  wire                     clear,

    input  wire                     input_valid,
    output wire                     input_ready,
    input  wire [WORD_WIDTH-1:0]    input_data,

    output wire [OUTPUT_COUNT-1:0]  output_valid,
    input  wire [OUTPUT_COUNT-1:0]  output_ready,
    output wire [TOTAL_WIDTH-1:0]   output_data
);

    wire [OUTPUT_COUNT-1:0] output_valid_unbuffered;
    wire [OUTPUT_COUNT-1:0] output_ready_unbuffered;
    wire [TOTAL_WIDTH-1:0]  output_data_unbuffered;

    Pipeline_Fork_Lazy
    #(
        .WORD_WIDTH     (WORD_WIDTH),
        .OUTPUT_COUNT   (OUTPUT_COUNT)
    )
    input_fork
    (
        .input_valid    (input_valid),
        .input_ready    (input_ready),
        .input_data     (input_data),

        .output_valid   (output_valid_unbuffered),
        .output_ready   (output_ready_unbuffered),
        .output_data    (output_data_unbuffered)
    );

    generate
        genvar i;
        for (i=0; i < OUTPUT_COUNT; i=i+1) begin: per_output
            Pipeline_Skid_Buffer
            #(
                .WORD_WIDTH      (WORD_WIDTH),
                .CIRCULAR_BUFFER (0)            // Not meaningful here
            )
            output_buffer
            (
                .clock           (clock),
                .clear           (clear),

                .input_valid     (output_valid_unbuffered [i]),
                .input_ready     (output_ready_unbuffered [i]),
                .input_data      (output_data_unbuffered  [WORD_WIDTH*i +: WORD_WIDTH]),

                .output_valid    (output_valid [i]),
                .output_ready    (output_ready [i]),
                .output_data     (output_data  [WORD_WIDTH*i +: WORD_WIDTH])
            );
        end
    endgenerate

endmodule

//# One-Hot Demultiplexer

// Connects the `word_in` input port to one of the words in the `words_out`
// output port, as selected by the `selectors` one-hot vector, and raises the
// corresponding valid bit in the `valids_out` output port.  *If more than one
// bit is set in the `selectors` input, then all the corresponding output
// words will get the input word value.*

//## Implementation Options

// Set the `BROADCAST` parameter to 1 to simply replicate and connect
// `word_in` to each word in `words_out`, without any logic. The valid bit
// will indicate which downstream logic should accept the data, and other
// logic can snoop the data if that's part of your larger design.

// Set the `BROADCAST` parameter to 0 to send `word_in` to *only* the selected
// word in `words_out`, whose valid bit is set. All other output words are
// annulled to zero. If no valid bit is set, all output words stay at zero.

// Not broadcasting the input to the output costs some logic, but less than it
// appears from a standalone synthesis of the demultiplexer: the inferred
// [Annullers](./Annuller.html) will very likely disappear into downstream LUT
// logic, it also makes tracing a simulation easier, and adds some design
// security and robustness since unselected downstream logic cannot snoop or
// accidentally receive other data.

// If necessary, select the Annuller `IMPLEMENTATION` which yields the best
// logic synthesis. Usually, this does not matter, and can be set to "AND".

// Setting `BROADCAST` to any value other than 1 or 0 will disconnect
// `word_in` from `words_out`, raise some critical warnings in your CAD tool,
// and generally cause a lot of downstream logic to optimize away, so you
// should notice...

`default_nettype none

module Demultiplexer_One_Hot
#(
    parameter       BROADCAST           = 0,
    parameter       WORD_WIDTH          = 0,
    parameter       OUTPUT_COUNT        = 0,
    parameter       IMPLEMENTATION      = "AND",

    // Do not set at instantiation
    parameter   TOTAL_WIDTH = WORD_WIDTH * OUTPUT_COUNT
)
(
    input   wire    [OUTPUT_COUNT-1:0]  selectors,
    input   wire    [WORD_WIDTH-1:0]    word_in,
    output  reg     [TOTAL_WIDTH-1:0]   words_out,
    output  reg     [OUTPUT_COUNT-1:0]  valids_out
);

    localparam OUTPUT_ZERO = {OUTPUT_COUNT{1'b0}};
    localparam TOTAL_ZERO  = {TOTAL_WIDTH{1'b0}};

    initial begin
        words_out  = TOTAL_ZERO;
        valids_out = OUTPUT_ZERO;
    end

// Pass along the selector to the downstream logic, so we know which output
// word is the selected one.

    always @(*) begin
        valids_out = selectors;
    end

// If we are *not* broadcasting, then for each output word, annul the output
// if its selector bit is not set.  Thus, only the selected output word will
// have the `word_in` data. All others will stay at zero.  Otherwise, simply
// replicate and connect the input to all outputs. 

    generate
        if (BROADCAST == 0) begin : gen_no_broadcast
            wire [TOTAL_WIDTH-1:0] words_out_internal;

            genvar i;
            for (i=0; i < OUTPUT_COUNT; i=i+1) begin: per_output
                Annuller
                #(
                    .WORD_WIDTH     (WORD_WIDTH),
                    .IMPLEMENTATION (IMPLEMENTATION)
                )
                output_gate
                (
                    .annul          (selectors[i] == 1'b0),
                    .data_in        (word_in),
                    .data_out       (words_out_internal[WORD_WIDTH*i +: WORD_WIDTH])
                );
            end

            always @(*) begin
                words_out = words_out_internal;
            end
        end
        else
        if (BROADCAST == 1) begin : gen_broadcast
            always @(*) begin
                words_out = {OUTPUT_COUNT{word_in}};
            end
        end
    endgenerate

endmodule
